  '{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[{"@type":"Question","name":"What is WhatsApp Business API?","acceptedAnswer":{"@type":"Answer","text":"WhatsApp Business API is a solution for businesses to send messages at scale, automate conversations, and manage customer communication professionally."}},{"@type":"Question","name":"How much does WhatsApp API cost in India?","acceptedAnswer":{"@type":"Answer","text":"The cost includes Meta conversation charges and platform fees, which can range from ₹0 to ₹10,000+ per month depending on the provider."}},{"@type":"Question","name":"Can I send bulk messages using WhatsApp API?","acceptedAnswer":{"@type":"Answer","text":"Yes, but only using approved message templates and with user consent."}},{"@type":"Question","name":"Is WhatsApp API better than WhatsApp Business App?","acceptedAnswer":{"@type":"Answer","text":"Yes, WhatsApp API offers automation, multi-user access, CRM integration, and scalability which are not available in the standard app."}}]}'::jsonb,
